SELECT [Sales Header].No_ AS NumeroOrdine, [Sales Header].[Bill-to Name] AS Cliente, [Sales Header].[VAT Registration No_] AS PIVA, Sum(Val([quantity])) AS [Pezzi/Paia], "Calzature e abbigliamento da uomo/donna" AS Prodotto, Sum(Val([Amount Including VAT])) AS importoIvaInclusa, Sum(Val([Line Amount])-Val([inv_ discount amount])) AS ValoreIvaEsclusa, Item.[Season Code], [Sales Header].[Bill-to Country Code], [Sales Header].[Payment Method Code], Item.[Trademark Code], [Sales Header].[Document Type], IIf([Consignment]=1,"Conto Vendita","") AS ContoVendita
FROM ([Sales Line] INNER JOIN [Sales Header] ON ([Sales Line].[Document No_] = [Sales Header].No_) AND ([Sales Line].[Document Type] = [Sales Header].[Document Type])) INNER JOIN Item ON [Sales Line].[Model Item No_] = Item.No_
GROUP BY [Sales Header].No_, [Sales Header].[Bill-to Name], [Sales Header].[VAT Registration No_], "Calzature e abbigliamento da uomo/donna", Item.[Season Code], [Sales Header].[Bill-to Country Code], [Sales Header].[Payment Method Code], Item.[Trademark Code], [Sales Header].[Document Type], [Sales Line].Type, [Sales Line].[Delete Reason], IIf([Consignment]=1,"Conto Vendita","")
HAVING (((Item.[Season Code])=[FiltroStagione]) AND (([Sales Header].[Document Type])=1) AND (([Sales Line].Type)=2) AND (([Sales Line].[Delete Reason])=""));

